UPDATE words SET example_en_2 = 'Zoom in to see the details of the map.', example_ko_2 = '지도의 세부 사항을 보려면 확대해 주세요.', example_en_3 = 'She zoomed in on the photo to read the small text.', example_ko_3 = '그녀는 작은 글씨를 읽으려고 사진을 확대했어요.', example_en_4 = 'You can zoom in and out using two fingers.', example_ko_4 = '두 손가락으로 확대하거나 축소할 수 있어요.', example_en_5 = 'I zoomed out to see the whole page at once.', example_ko_5 = '한 번에 전체 페이지를 보기 위해 축소했어요.' WHERE id = 'w_technology_A2_27';
UPDATE words SET example_en_2 = 'What format should I save the file in?', example_ko_2 = '파일을 어떤 형식으로 저장해야 하나요?', example_en_3 = 'The video format isn''t supported by this device.', example_ko_3 = '이 기기에서 지원하지 않는 영상 형식이에요.', example_en_4 = 'Please convert the document to PDF format.', example_ko_4 = '문서를 PDF 형식으로 변환해 주세요.', example_en_5 = 'The data is exported in CSV format for easy use.', example_ko_5 = '데이터는 편리하게 사용할 수 있도록 CSV 형식으로 내보내져요.' WHERE id = 'w_technology_A2_28';
UPDATE words SET example_en_2 = 'I was streaming music while working.', example_ko_2 = '일하면서 음악을 스트리밍하고 있었어요.', example_en_3 = 'The stream kept buffering because of the slow connection.', example_ko_3 = '연결 속도가 느려서 스트림이 계속 버퍼링됐어요.', example_en_4 = 'She streams live on social media every Friday.', example_ko_4 = '그녀는 매주 금요일에 소셜 미디어에서 라이브 스트리밍을 해요.', example_en_5 = 'I don''t buy CDs anymore — I just stream everything.', example_ko_5 = '저는 더 이상 CD를 사지 않아요. 모든 것을 스트리밍해요.' WHERE id = 'w_technology_A2_29';
UPDATE words SET example_en_2 = 'I can''t connect to the printer from my laptop.', example_ko_2 = '노트북에서 프린터에 연결할 수 없어요.', example_en_3 = 'Connect the device using the cable provided.', example_ko_3 = '제공된 케이블을 사용해서 기기를 연결해 주세요.', example_en_4 = 'The app connects automatically when you open it.', example_ko_4 = '앱을 열면 자동으로 연결돼요.', example_en_5 = 'She connected to the VPN before accessing company files.', example_ko_5 = '그녀는 회사 파일에 접근하기 전에 VPN에 연결했어요.' WHERE id = 'w_technology_A2_30';
UPDATE words SET example_en_2 = 'The app crashed and I lost my progress.', example_ko_2 = '앱이 충돌해서 진행 상황을 잃어버렸어요.', example_en_3 = 'The system crashed right before I saved my work.', example_ko_3 = '작업을 저장하기 직전에 시스템이 다운됐어요.', example_en_4 = 'The website keeps crashing — is it down for everyone?', example_ko_4 = '웹사이트가 계속 다운돼요. 모두에게 그런 건가요?', example_en_5 = 'He had to reboot after the program crashed.', example_ko_5 = '프로그램이 다운된 후 재부팅해야 했어요.' WHERE id = 'w_technology_A2_31';
UPDATE words SET example_en_2 = 'Tap the icon to open the app.', example_ko_2 = '앱을 열려면 아이콘을 탭하세요.', example_en_3 = 'Tap and hold to move an icon to a different place.', example_ko_3 = '길게 탭해서 아이콘을 다른 위치로 이동하세요.', example_en_4 = 'She tapped "Share" and sent the photo instantly.', example_ko_4 = '그녀는 "공유"를 탭해서 즉시 사진을 보냈어요.', example_en_5 = 'Double-tap the screen to zoom in.', example_ko_5 = '화면을 두 번 탭하면 확대돼요.' WHERE id = 'w_technology_A2_32';
UPDATE words SET example_en_2 = 'Swipe left to delete the message.', example_ko_2 = '메시지를 삭제하려면 왼쪽으로 스와이프하세요.', example_en_3 = 'Swipe up from the bottom to go back to the home screen.', example_ko_3 = '홈 화면으로 돌아가려면 하단에서 위로 스와이프하세요.', example_en_4 = 'She swiped through her photos looking for the right one.', example_ko_4 = '그녀는 원하는 사진을 찾으려고 사진을 스와이프하며 봤어요.', example_en_5 = 'Swipe right to accept and swipe left to decline.', example_ko_5 = '오른쪽으로 스와이프하면 수락, 왼쪽으로 스와이프하면 거절이에요.' WHERE id = 'w_technology_A2_33';
UPDATE words SET example_en_2 = 'The video resolution is set to 1080p for better quality.', example_ko_2 = '더 좋은 화질을 위해 영상 해상도를 1080p로 설정했어요.', example_en_3 = 'Lower the resolution to save data when streaming.', example_ko_3 = '스트리밍할 때 데이터를 절약하려면 해상도를 낮추세요.', example_en_4 = 'The photo''s resolution is too low to print clearly.', example_ko_4 = '사진 해상도가 너무 낮아서 선명하게 출력할 수 없어요.', example_en_5 = 'The new monitor supports 4K resolution.', example_ko_5 = '새 모니터는 4K 해상도를 지원해요.' WHERE id = 'w_technology_A2_34';
UPDATE words SET example_en_2 = 'The notification badge showed I had twelve unread messages.', example_ko_2 = '알림 배지에 읽지 않은 메시지가 12개 있다고 나왔어요.', example_en_3 = 'I turned off notification badges because they distract me.', example_ko_3 = '집중에 방해가 돼서 알림 배지를 껐어요.', example_en_4 = 'The red badge on the app icon means there is a new update.', example_ko_4 = '앱 아이콘의 빨간 배지는 새 업데이트가 있다는 뜻이에요.', example_en_5 = 'She noticed the notification badge and opened the app immediately.', example_ko_5 = '그녀는 알림 배지를 보고 즉시 앱을 열었어요.' WHERE id = 'w_technology_A2_35';
